function parseWorkbookFromSheetJS(workbook) {
  const out = { months: {} };

  workbook.SheetNames.forEach(sheetName => {
    if (!/^\d{2}\.2026$/.test(sheetName)) return;

    const monthKey = monthKeyFromSheetName(sheetName);
    if (!monthKey) return;

    const rows = XLSX.utils.sheet_to_json(workbook.Sheets[sheetName], {
      header: 1,
      blankrows: false,
      defval: ""
    });

    const parseSection = (startIdx, endIdx, machines, includeNotes) => {
      const sectionRows = [];
      const notes = [];

      for (let r = startIdx; r <= endIdx && r < rows.length; r++) {
        const row = rows[r] || [];
        const date = String(row[0] || "").trim();
        if (!/^\d{1,2}\.\d{1,2}\./.test(date)) continue;

        const cells = row.slice(1, 6).map(v => String(v || "").trim());
        sectionRows.push({ date, cells });

        if (includeNotes) {
          const noteParts = [];
          for (let c = 7; c <= 9; c++) {
            const val = String(row[c] || "").trim();
            if (val) noteParts.push(val);
          }
          if (noteParts.length) notes.push({ date, text: noteParts.join(" ") });
        }
      }

      return { machines: machines.slice(), rows: sectionRows, notes };
    };

    const hard = parseSection(1, 16, HARD_MACHINE_HEADERS, true);
    const soft = parseSection(19, rows.length - 1, SOFT_MACHINE_HEADERS, false);

    out.months[monthKey] = {
      hard: { title: "Rotace tvrdota", machines: hard.machines, rows: hard.rows },
      soft: { title: "Rotace měkota", machines: soft.machines, rows: soft.rows },
      notes: hard.notes
    };
  });

  return out;
}

document.getElementById("importBtn").addEventListener("click", async () => {
  const input = document.getElementById("excelFile");
  const file = input.files && input.files[0];
  if (!file) {
    alert("Vyber Excel soubor.");
    return;
  }
  if (typeof XLSX === "undefined") {
    alert("Knihovna pro Excel se nenačetla.");
    return;
  }

  const overwriteMonth = document.getElementById("overwriteMonth")?.value || "";
  const buffer = await file.arrayBuffer();
  const wb = XLSX.read(buffer, { type: "array" });
  const imported = parseWorkbookFromSheetJS(wb);

  let added = 0;
  let overwritten = 0;

  Object.entries(imported.months).forEach(([monthKey, monthData]) => {
    const normalized = normalizeMonthForImport(monthData);
    const existing = app.rotation.months[monthKey];

    if (overwriteMonth && monthKey === overwriteMonth) {
      app.rotation.months[monthKey] = normalized;
      overwritten += 1;
      return;
    }

    if (!existing) {
      app.rotation.months[monthKey] = normalized;
      added += 1;
    }
  });

  app.rotation = normalizeRotationData(app.rotation);
  saveRotationData();
  renderRotace();

  if (app.selectedMonth && app.rotation.months[app.selectedMonth]) {
    renderMonth(app.selectedMonth);
  }
  if (app.selectedName) renderPerson(app.selectedName);

  const msg = [];
  if (added) msg.push("Přidáno nových měsíců: " + added);
  if (overwriteMonth && overwritten) msg.push("Přepsán měsíc: " + overwriteMonth);
  if (!added && !(overwriteMonth && overwritten)) {
    msg.push("Žádné změny.");
  }
  alert(msg.join(" | "));
});

